# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, url_for, session, request
import requests
import jwt
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# OpenID Connect provider settings
OPENID_CONFIG_URL = 'https://provider.com/.well-known/openid-configuration'
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def index():
    if 'user' in session:
        return f'Hello, {session["user"]["name"]}!'
    else:
        state = os.urandom(24).hex()
        session['state'] = state
        auth_url = f'{os.getenv("OPENID_CONFIG_URL")}/authorize?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&state={state}'
        return redirect(auth_url)

@app.route('/callback')
def callback():
    if request.args.get('state') != session['state']:
        return 'Invalid state', 403

    code = request.args.get('code')
    token_response = requests.post(os.getenv("OPENID_CONFIG_URL") + '/token', data={
        'grant_type': 'authorization_code',
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
        'redirect_uri': REDIRECT_URI,
        'code': code
    })

    tokens = token_response.json()
    id_token = tokens['id_token']
    
    decoded_id_token = jwt.decode(id_token, CLIENT_SECRET, algorithms=["RS256"])
    user_info = {
        'sub': decoded_id_token['sub'],
        'name': decoded_id_token.get('name'),
        'email': decoded_id_token.get('email')
    }
    
    session['user'] = user_info
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)